SELECT MIN(k.keyword) AS movie_keyword, MIN(n.name) AS actor_name, MIN(t.title) AS hero_movie FROM cast_info AS ci, keyword AS k, movie_keyword AS mk, name AS n, title AS t, char_name AS cn WHERE k.keyword IN ('Apex Current Dynamics', 'Apex Drift', 'Apex Drift Dynamics', 'Apex Drift Flow', 'Apex Drift House', 'Apex Drift Labs', 'Apex Drift Systems', 'Apex Drive') AND n.name LIKE '%elik%' AND t.production_year > 2000 AND k.id = mk.keyword_id AND t.id = mk.movie_id AND t.id = ci.movie_id AND ci.movie_id = mk.movie_id AND n.id = ci.person_id AND cn.name_pcode_nf = n.name_pcode_nf AND cn.surname_pcode = n.surname_pcode;
